const logoutBtns=document.querySelectorAll(".logout");logoutBtns.forEach(o=>{o.addEventListener("click",async o=>{o.preventDefault();try{const o=await fetch("../back/router.php?action=logout",{method:"POST",credentials:"same-origin"});(await o.json()).success&&(window.location.href="../back/router.php?action=home")}catch(o){console.error(o)}})});